// src/node_modules/@sudoku/stores/explore.js
import { writable } from 'svelte/store';
import { cloneSudoku } from '@sudoku/sudoku';

function createExplore() {
	const isExploring = writable(false);
	const exploreStartGrid = writable(null); // 探索开始时的棋盘快照

	return {
		subscribe: isExploring.subscribe,
		
		// 进入探索模式
		enterExplore(currentGrid) {
			isExploring.set(true);
			exploreStartGrid.set(cloneSudoku(currentGrid));
		},

		// 提交探索结果
		commitExplore() {
			isExploring.set(false);
			exploreStartGrid.set(null);
		},

		// 放弃探索，回滚
		abandonExplore() {
			let gridToRestore = null;
			// 这里的语法是临时订阅获取值
			const unsubscribe = exploreStartGrid.subscribe(g => {
				if (g) gridToRestore = cloneSudoku(g);
			});
			unsubscribe();
			
			isExploring.set(false);
			exploreStartGrid.set(null);
			
			return gridToRestore;
		}
	};
}

export const explore = createExplore();
